import { tags } from 'decantr/tags';
import { createSignal, createMemo } from 'decantr/state';
import { css } from 'decantr/css';
import { DataTable, Input, Select, Button, Badge } from 'decantr/components';

code.example:
function DataTablePattern({ search: extSearch, status: extStatus, onSearch, onStatus } = {}) {
  const { div } = tags;
  const [_search, _setSearch] = createSignal('');
  const [_status, _setStatus] = createSignal('all');
  const search = extSearch || _search;
  const setSearch = v => { _setSearch(v); onSearch?.(v); };
  const status = extStatus || _status;
  const setStatus = v => { _setStatus(v); onStatus?.(v); };
  const columns = [
    { key: 'name', label: 'Name', sortable: true },
    { key: 'email', label: 'Email', sortable: true },
    { key: 'role', label: 'Role' },
    { key: 'status', label: 'Status' }
  ];
  const rawData = [
    { name: 'Alice Chen', email: 'alice@example.com', role: 'Admin', status: 'active' },
    { name: 'Bob Patel', email: 'bob@example.com', role: 'Editor', status: 'active' },
    { name: 'Carol Liu', email: 'carol@example.com', role: 'Viewer', status: 'inactive' },
    { name: 'Dan Kim', email: 'dan@example.com', role: 'Editor', status: 'active' }
  ];
  const filteredData = createMemo(() => {
    let rows = rawData;
    const s = search().toLowerCase();
    if (s) rows = rows.filter(r => Object.values(r).some(v => String(v).toLowerCase().includes(s)));
    const st = status();
    if (st !== 'all') rows = rows.filter(r => r.status === st);
    return rows;
  });
  const exportCsv = () => {
    const rows = filteredData();
    if (!rows.length) return;
    const keys = Object.keys(rows[0]);
    const csv = [keys.join(','), ...rows.map(r => keys.map(k => String(r[k])).join(','))].join('\n');
    const blob = new Blob([csv], { type: 'text/csv' });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = 'export.csv';
    a.click();
    URL.revokeObjectURL(a.href);
  };

  return div({ class: css('_flex _col _gap4') },
    div({ class: css('_flex _gap3 _aic _jcsb') },
      Input({ placeholder: 'Search...', value: search, onchange: e => setSearch(e.target.value) }),
      div({ class: css('_flex _gap2') },
        Select({ value: status, onchange: v => setStatus(v), options: [
          { label: 'All', value: 'all' },
          { label: 'Active', value: 'active' },
          { label: 'Inactive', value: 'inactive' }
        ] }),
        Button({ variant: 'outline', onclick: exportCsv }, 'Export')
      )
    ),
    DataTable({ columns, data: filteredData, sortable: true, paginate: true, pageSize: 10 })
  );
}

