function AuditLog({ entries: extEntries, level: extLevel, onLevel } = {}) {
  const { div, span } = tags;
  const [_level, _setLevel] = createSignal('all');
  const level = extLevel || _level;
  const setLevel = v => { _setLevel(v); onLevel?.(v); };
  const sevVariant = s => s === 'critical' ? 'error' : s === 'warning' ? 'warning' : s === 'info' ? 'info' : 'default';
  const defaultEntries = [
    { severity: 'critical', timestamp: '2024-03-15 14:23', actor: 'system', action: 'Service restart', target: 'api-gateway' },
    { severity: 'warning', timestamp: '2024-03-15 14:20', actor: 'alice@co.com', action: 'Permission change', target: 'user:bob' },
    { severity: 'info', timestamp: '2024-03-15 14:15', actor: 'bob@co.com', action: 'Login', target: 'dashboard' },
    { severity: 'info', timestamp: '2024-03-15 14:10', actor: 'carol@co.com', action: 'Export data', target: 'reports' }
  ];
  const rawEntries = extEntries || defaultEntries;
  const filteredEntries = createMemo(() => {
    const l = level();
    return l === 'all' ? rawEntries : rawEntries.filter(e => e.severity === l);
  });

  const columns = [
    { key: 'severity', label: 'Severity', render: row => Badge({ variant: sevVariant(row.severity), size: 'sm' }, row.severity) },
    { key: 'timestamp', label: 'Timestamp', sortable: true },
    { key: 'actor', label: 'Actor', sortable: true },
    { key: 'action', label: 'Action' },
    { key: 'target', label: 'Target' }
  ];
  const exportCsv = () => {
    const rows = filteredEntries();
    if (!rows.length) return;
    const keys = Object.keys(rows[0]);
    const csv = [keys.join(','), ...rows.map(r => keys.map(k => String(r[k])).join(','))].join('\n');
    const blob = new Blob([csv], { type: 'text/csv' });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = 'audit-log.csv';
    a.click();
    URL.revokeObjectURL(a.href);
  };

  return div({ class: css('_flex _col _gap3') },
    div({ class: css('_flex _gap3 _aic') },
      Select({ value: level, onchange: v => setLevel(v), options: [
        { label: 'All Levels', value: 'all' },
        { label: 'Critical', value: 'critical' },
        { label: 'Warning', value: 'warning' },
        { label: 'Info', value: 'info' }
      ] }),
      Button({ variant: 'outline', size: 'sm', onclick: exportCsv }, icon('download', { size: '1em' }), ' Export')
    ),
    DataTable({ columns, data: filteredEntries, sortable: true, paginate: true, pageSize: 20 })
  );
}

