    { id: 2, name: 'Bob Patel', email: 'bob@example.com', role: 'Editor', status: 'active', joined: 'Mar 2024', bio: 'Content editor' },
    { id: 3, name: 'Carol Liu', email: 'carol@example.com', role: 'Viewer', status: 'inactive', joined: 'Jun 2024', bio: 'Read-only access' }
  ];

  return div({ class: css('_grid _gc1 _lg:gc3 _gap4') },
    div({ class: css('_lg:span2 _flex _col _gap3') },
      Input({ placeholder: 'Search users...', class: css('_wfull') }),
      DataTable({ columns, data, sortable: true, paginate: true, pageSize: 10, onRowClick: row => setSelected(row) })
    ),
    () => selected() ? Card({},
      Card.Header({}, h3({ class: css('_heading5') }, selected().name)),
      Card.Body({},
        div({ class: css('_flex _col _gap3') },
          div({}, span({ class: css('_textxs _fgmuted') }, 'Email'), p({ class: css('_textsm') }, selected().email)),
          div({}, span({ class: css('_textxs _fgmuted') }, 'Role'), p({ class: css('_textsm') }, selected().role)),
          div({}, span({ class: css('_textxs _fgmuted') }, 'Joined'), p({ class: css('_textsm') }, selected().joined)),
          div({}, span({ class: css('_textxs _fgmuted') }, 'Bio'), p({ class: css('_textsm') }, selected().bio)),
          div({ class: css('_flex _gap2 _mt2') },
            Button({ variant: 'primary', size: 'sm' }, 'Edit'),
            Button({ variant: 'outline', size: 'sm' }, 'Delete')
          )
        )
      )
    ) : div({ class: css('_flex _center _h[300px] _fgmuted _textsm') }, 'Select a row to view details')
  );
}

