function DataTableEditable() {
  const { div } = tags;
  const [rows, setRows] = createStore([
    { id: 1, name: 'Alice Chen', email: 'alice@example.com', role: 'Admin', editing: false },
    { id: 2, name: 'Bob Patel', email: 'bob@example.com', role: 'Editor', editing: false },
    { id: 3, name: 'Carol Liu', email: 'carol@example.com', role: 'Viewer', editing: false }
  ]);
  let nextId = 4;

  const toggleEdit = id => setRows(rows.map(r => r.id === id ? { ...r, editing: !r.editing } : r));
  const updateField = (id, key, val) => setRows(rows.map(r => r.id === id ? { ...r, [key]: val } : r));
  const deleteRow = id => setRows(rows.filter(r => r.id !== id));
  const addRow = () => setRows([...rows, { id: nextId++, name: '', email: '', role: 'Viewer', editing: true }]);

  const columns = [
    { key: 'name', label: 'Name', render: row => row.editing ? Input({ value: row.name, onchange: e => updateField(row.id, 'name', e.target.value), size: 'sm' }) : row.name },
    { key: 'email', label: 'Email', render: row => row.editing ? Input({ value: row.email, onchange: e => updateField(row.id, 'email', e.target.value), size: 'sm' }) : row.email },
    { key: 'role', label: 'Role', render: row => row.editing ? Select({ value: row.role, onchange: v => updateField(row.id, 'role', v), options: [{ label: 'Admin', value: 'Admin' }, { label: 'Editor', value: 'Editor' }, { label: 'Viewer', value: 'Viewer' }], size: 'sm' }) : row.role },
    { key: 'actions', label: '', render: row => div({ class: css('_flex _gap1') },
      Button({ variant: 'ghost', size: 'sm', onclick: () => toggleEdit(row.id) }, icon(row.editing ? 'check' : 'edit', { size: '1em' })),
      Button({ variant: 'ghost', size: 'sm', onclick: () => deleteRow(row.id) }, icon('trash', { size: '1em' }))
    ) }
  ];

  return div({ class: css('_flex _col _gap4') },
    div({ class: css('_flex _jce') },
      Button({ variant: 'primary', size: 'sm', onclick: addRow }, icon('plus', { size: '1em' }), ' Add Row')
    ),
    DataTable({ columns, data: rows, paginate: true, pageSize: 10 })
  );
}

